+        conn.execute_with_params(
+            "INSERT INTO documents (\
+                doc_id, content_preview, content_hash, content_length, created_at, updated_at\
+             ) VALUES (?1, ?2, ?3, ?4, ?5, ?6);",
+            &params,
+        )
+        .map_err(super::map_storage_error)?;
