+        assert!(fm.focus("z"));
+        assert_eq!(fm.focused(), Some("z"));
+        assert!(!fm.focus("nonexistent"));
+    }
+
+    #[test]
+    fn focus_manager_clear() {
+        let mut fm = FocusManager::new();
