+
+    #[test]
+    fn semantic_role_display() {
+        assert_eq!(SemanticRole::Region.to_string(), "region");
+        assert_eq!(SemanticRole::Navigation.to_string(), "navigation");
+        assert_eq!(SemanticRole::Grid.to_string(), "grid");
