+    #[test]
+    fn resolve_unknown_returns_none() {
+        let keymap = Keymap::default_bindings();
+        assert!(keymap.resolve(KeyCode::Char('z'), KeyModifiers::NONE).is_none());
+    }
+
+    #[test]
+    fn custom_binding() {
+        let mut keymap = Keymap::default_bindings();
