+    }
+
+    #[test]
+    fn palette_register_and_count() {
+        let palette = sample_palette();
+        assert_eq!(palette.len(), 4);
+    }
+
+    #[test]
+    fn palette_toggle() {
+        let mut palette = sample_palette();
+        assert_eq!(palette.state(), &PaletteState::Closed);
+        palette.toggle();
+        assert_eq!(palette.state(), &PaletteState::Open);
+        palette.toggle();
+        assert_eq!(palette.state(), &PaletteState::Closed);
+    }
