+    #[test]
+    fn palette_filter_empty_query() {
+        let palette = sample_palette();
+        assert_eq!(palette.filtered().len(), 4);
+    }
+
+    #[test]
+    fn palette_filter_by_label() {
+        let mut palette = sample_palette();
+        palette.open();
